    e1ap_setup_fail_t setup_fail = {.transac_id = E1AP_SETUP_REQ(msg_p).transac_id, .cause = cause};
    e1apCUCP_send_SETUP_FAILURE(assoc_id, &setup_fail);
    itti_free(TASK_CUCP_E1, msg_p);

